#include <stdio.h>
#include <stdlib.h>
#define MAXN 100000
int main(){
    static long long f[MAXN+1];
    static long long pref[MAXN+1];
    // compute f using odd divisors
    for(int d=1; d<=MAXN; d+=2){
        for(int j=d; j<=MAXN; j+=d){
            f[j] += d;
        }
    }
    pref[0]=0;
    for(int i=1;i<=MAXN;i++) pref[i]=pref[i-1]+f[i];
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int l,r; scanf("%d %d",&l,&r);
        long long ans = pref[r] - pref[l-1];
        printf("%lld\n", ans);
    }
    return 0;
}

